<!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/>
    <title>ENT uahb — Réinitialisation</title>
    <link href="https://fonts.googleapis.com/css2?family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&family=DM+Sans:wght@300;400;500;600&display=swap" rel="stylesheet"/>
    <link href="/personnel/ressources/dist_assets/plugins/global/plugins.bundle.css" rel="stylesheet" type="text/css"/>
    <link href="/personnel/ressources/dist_assets/css/style.bundle.css" rel="stylesheet" type="text/css"/>
    <link rel="stylesheet" type="text/css" href="/personnel/ressources/dist_assets/css/reset.css">
</head>
<body>

<header class="m-head">
    <div class="m-head-in">
        <div class="m-brand">
            <img src="data:image/png;base64," alt="uahb" class="m-logo"/>
            <div><div class="m-name">ENT — uahb</div><div class="m-sub">Portail Numérique</div></div>
        </div>
        <a href="/signIn" class="m-btn">Se connecter</a>
    </div>
</header>

<div class="layout">
    <div class="photo-panel">
        <div class="pp-img" style="background-image:url('data:image/jpeg;base64,')"></div>
        <div class="pp-tint"></div>
        <div class="pp-grain"></div>
        <div class="pp-top">
            <a href="index.html" class="pp-brand">
                <img src="data:image/png;base64," alt="uahb" class="pp-logo"/>
                <div>
                    <div class="pp-brand-n">ENT — uahb</div>
                    <div class="pp-brand-s">Portail Numérique</div>
                </div>
            </a>
            <a href="index.html" class="pp-home">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>
                Accueil
            </a>
        </div>
        <div class="pp-scroll"><div class="ps-line"></div><span class="ps-txt">Défiler</span></div>
        <div class="pp-body">
            <div class="pp-tag" style="animation-delay:.05s">
                <span class="pp-tag-dot" style="background:#22C55E;color:#22C55E"></span>
                <span class="pp-tag-txt">Récupération d'accès</span>
            </div>
            <div class="pp-rule" style="animation-delay:.2s"></div>
            <h2 class="pp-h" style="animation-delay:.15s">Récupérez votre<br/><em>mot de passe</em></h2>
            <p class="pp-p" style="animation-delay:.25s">Suivez les 3 étapes pour retrouver l'accès à votre compte ENT en toute sécurité.</p>
            <div class="pp-pills" style="animation-delay:.35s">
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#22C55E"></span>UAHB</div>
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#D97706"></span>uahb</div>
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#22C55E"></span>CTD</div>
            </div>
        </div>
    </div>
    <div class="form-panel">
        <div class="form-inner">
            <div class="steps-bar">
                <div class="sd active"></div><div class="sd"></div><div class="sd"></div>
            </div>

            <!-- Étape 1 -->
            <div class="panel active" id="p1">
                <div class="fh">
                    <div class="fh-eyebrow">Étape 1 sur 3</div>
                    <h1 class="fh-title">Mot de passe<br/><em>oublié ?</em></h1>
                    <div class="fh-rule"></div>
                    <p class="fh-sub">Entrez votre email pour recevoir un code de vérification.</p>
                </div>
                <div class="ff">
                    <label>Email institutionnel</label>
                    <div class="iw">
                        <svg class="ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M20 4H4a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V6a2 2 0 0 0-2-2z"/><polyline points="22,6 12,13 2,6"/></svg>
                        <input class="inp" id="ei" type="email" name="email" placeholder="prenom.nom@uahb.sn"/>
                    </div>
                </div>
                <button class="btn-main" onclick="goStep(2)">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
                    Envoyer le code
                </button>
                <div class="back-lnk"><a href="/signIn"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="15 18 9 12 15 6"/></svg>Retour à la connexion</a></div>
            </div>
            <div class="f-foot">
                <span class="ep"><span class="ep-dot epg"></span>UAHB</span>
                <span class="ep"><span class="ep-dot epb"></span>uahb</span>
                <span class="ep"><span class="ep-dot epc"></span>CTD</span>
            </div>


        </div>
    </div>
</div>


<script src="/personnel/ressources/dist_assets/plugins/global/plugins.bundle.js"></script>
<script src="/personnel/ressources/dist_assets/js/scripts.bundle.js"></script>
<script src="/personnel/scripts.bundle.4.js"></script>

</body></html>